css:
.loader {color: var(--loader-color, #7c3aed);
  --loader-secondary-color: #c084fc;
  --loader-bg: #ffffff;
  width: 50px;
  aspect-ratio: 1;
  display: grid;
}.loader::before,.loader::after{content: "";
  grid-area: 1/1;
  border-radius: 50%;
  background: repeating-conic-gradient(#0000,currentColor 1deg 18deg,#0000 20deg 36deg);
  -webkit-mask: repeating-radial-gradient(farthest-side,currentColor 0 10%,#0000 0 20%);
  animation: l10 4s infinite linear;
}.loader::after{-webkit-mask: repeating-radial-gradient(farthest-side,#0000 0 10%,currentColor 0 20%);
  animation-direction: reverse;
}@keyframes l10 {100% {transform: rotate(.5turn)}}
